var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하... 쿨럭.","JPN":"はあ……ゲホッ。","ENG":"*Huff...* *Cough*","TWN":"咳……咳咳。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"드디어... 사라졌네.","JPN":"やっと……消えた。","ENG":"Finally... she's gone.","TWN":"終於……消失了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"방금 그 공격은, 뭐였죠?","JPN":"今の攻撃は、何だったのですか？","ENG":"What was that attack just now?","TWN":"剛剛那個攻擊，是什麼？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클레시아에게... 딱 한 방만 먹이면 된다고 했거든.","JPN":"エクレシアに……たった一発食らわせればいいって言ったの。","ENG":"I told her that she... only needed to land a single hit on Ecclesia.","TWN":"我說過……只要讓艾可露西亞吃上一擊就行了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"네 소망으로 만들어진 존재한테 먹히는 걸 보면... 확실히 걔도 보통은 아닌 거 같아. 안 그래?","JPN":"君の願いで作られた存在に効くってことは……あの子も大したもんだね。","ENG":"Seeing as her attacks work even against a being born from your wish... she's definitely no ordinary girl. Don't you think?","TWN":"被你所願的存在擊中……看來那傢伙果然也不是普通人。不是嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"결국... 선을 넘어버리고 말았네요. 우리 모두.","JPN":"結局……線を超えてしまいましたね。私たち。","ENG":"In the end... we all crossed the line.","TWN":"結果……我們所有人，終究還是越過了那條線。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"해냈다. 정말로 해가 완전히 저물었어.","JPN":"やった。本当に完全に日が暮れた。","ENG":"I did it. The sun has really set completely.","TWN":"成功了。太陽真的完全落下了。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"이게... 밤.","JPN":"これが……夜。","ENG":"This is... night.","TWN":"這就是……夜晚。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"이리도 어두운데, 그 어느 때보다 드넓어 보이는 하늘이라니.","JPN":"空がこんなに暗いのに、どの時よりも広々と感じるだなんて。","ENG":"It's so dark, and yet the sky looks wider than ever before.","TWN":"明明這麼黑，天空卻看起來比任何時候都更遼闊。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...아름답구나.","JPN":"……美しい。","ENG":"...It's beautiful.","TWN":"……真美。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"저것은...?","JPN":"あれは……？","ENG":"What is that...?","TWN":"那是……？"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"드디어 밤이 됐네.","JPN":"やっと夜になったね。","ENG":"It's finally night.","TWN":"終於變成夜晚了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"역시, 시간을 되풀이하는 조건은 당신의 죽음이었던 거야.","JPN":"やっぱり、時を繰り返す条件は君の死だったんだ。","ENG":"Just as I thought, the condition for repeating time was your death.","TWN":"果然，時間反覆循環的條件就是你的死亡。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"...맞아요. 낙원의 운명은 저와 하나로 묶여있어서, 시작과 끝을 함께하거든요.","JPN":"……そうです。楽園の運命は私と一つになっていて、始まりと終わりを共有しているのです。","ENG":"...That's right. The fate of the Promised Land is bound together with mine, so it begins and ends with me.","TWN":"……沒錯。樂園的命運和我綁在一起，開始與結束都會同時發生。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"낙원은 제가 살아있길 바라기 때문에, 매일 죽음을 반복하며 종말을 피할 수 있는 거죠.","JPN":"楽園は私に生きていてほしいため、毎日死を繰り返すことで終末から逃れることができます。","ENG":"Because the Promised Land wishes for me to remain alive, I repeat my death every day to avoid its end.","TWN":"因為樂園希望我活著，所以只要我每天重複死亡，就能避開末日。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"창조주가 살아있으면 멸망하고 마는 세계라니. 참 기구한 아이러니네.","JPN":"創造主が生きていると滅ぶ世界だなんて、皮肉だね。","ENG":"A world that collapses if its creator stays alive. What a strange irony.","TWN":"只要創造者活著，世界反而會毀滅……真諷刺。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저 빛줄기는... 뭐지?","JPN":"あの光の筋は……何？","ENG":"That beam of light... what is it?","TWN":"那道光柱……是什麼？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"<color=#ffd34c>낙원문</color>이라 불리는 길이에요. 낙원의 안과 밖을 나누는 유일한 경계이기도 하죠.","JPN":"<color=#ffd34c>楽園の門</color>と呼ばれる道です。楽園の内と外を区別する、唯一の境界でもあります。","ENG":"It's a path called <color=#ffd34c>Avalon's Gate</color>. It's also the only boundary that separates the inside of the Promised Land from the outside.","TWN":"那是被稱為<color=#ffd34c>樂園門</color>的道路，也是分隔樂園內外的唯一界線。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"당신이 떠나고 싶다면, 저곳을 통해야만 나갈 수 있어요.","JPN":"あなたがここを離れたいなら、あそこを通るしかありません。","ENG":"If you want to leave, you can only exit through there.","TWN":"如果你想離開，就只能從那裡出去。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그렇다면 난 떠나겠어.","JPN":"……じゃあ私は行くよ。","ENG":"...Then I'll leave.","TWN":"……那我要離開。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"너도, 매일 죽는 고통을 느낄 바엔 순순히 현실을 받아들이고 떠나는 게 어때?","JPN":"君も、毎日死の苦しみを味わうくらいなら、大人しく現実を受け入れてここを離れたらどう？","ENG":"Rather than suffering through dying every day, how about you accept reality and leave as well?","TWN":"你也是。與其每天承受死亡的痛苦，不如乾脆接受現實離開怎麼樣？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그럴 순 없어요.","JPN":"そうはいきません。","ENG":"I can't do that.","TWN":"不行。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"전 문턱을 넘는 것만으론 헤어날 수 없을 만큼, 이미 너무 깊이 들어와 버린 걸요.","JPN":"すでに扉をくぐるだけでは逃れられないほど、深く関わってしまっていますから。","ENG":"I've already gone too deep to escape just by crossing the threshold.","TWN":"我已經深入到光是跨過門也無法脫身的程度了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"우리 세계를 네 낙원의 양분으로 만들 거라고 했지?","JPN":"私たちの世界を、楽園の養分にするって言ったよね。","ENG":"You said you were going to make our world into nutrients for your paradise, didn't you?","TWN":"你說過要把我們的世界變成你樂園的養分。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온은 실패할 거야. 그러니 네가 바라는 낙원이 완성될 일도 없을 테고.","JPN":"タギリオンは失敗するよ。だから君が望む楽園が完成することはない。","ENG":"Thagirion will fail. So the paradise you're hoping for will never be completed.","TWN":"塔基里翁會失敗的，所以你期望的樂園也不會完成。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"반드시 성공할 필요는 없어요.","JPN":"必ずしも成功する必要はありません。","ENG":"It doesn't need to succeed.","TWN":"不一定要成功。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"저에게 중요한 건, 완성까지 나아가는 과정이니...","JPN":"私にとって重要なのは、完成までの道のりですから……","ENG":"What matters to me is the process of moving toward completion...","TWN":"對我而言，重要的是走向完成的過程……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"윽, 무슨 짓이야?","JPN":"うっ、何をするの！","ENG":"Ugh, what are you doing?","TWN":"喂，你在做什麼？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};